    user_id character varying NOT NULL,
    period_year integer NOT NULL,
    annual_entitlement_days integer DEFAULT 14 NOT NULL,
    used_days integer DEFAULT 0 NOT NULL,
    carried_over_days integer DEFAULT 0 NOT NULL,
    remaining_days integer GENERATED ALWAYS AS (((annual_entitlement_days + carried_over_days) - used_days)) STORED,
    notes text,
    last_calculated_at timestamp without time zone DEFAULT now(),
    created_at timestamp without time zone DEFAULT now(),
    updated_at timestamp without time zone DEFAULT now()
);


--
-- Name: TABLE leave_balances; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.leave_balances IS 'Kullanıcı bazında yıllık izin bakiyesi (İş Kanunu Madde 53 uyumlu)';


--
-- Name: COLUMN leave_balances.annual_entitlement_days; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.leave_balances.annual_entitlement_days IS 'Yıllık izin hakkı (kıdem süresine göre)';


--
-- Name: COLUMN leave_balances.used_days; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.leave_balances.used_days IS 'O yıl kullanılan izin günü (leave_requests approved toplamı)';


--
-- Name: COLUMN leave_balances.carried_over_days; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.leave_balances.carried_over_days IS 'Önceki yıldan devreden gün (max 14)';


--
-- Name: COLUMN leave_balances.remaining_days; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.leave_balances.remaining_days IS 'Hesaplanan: entitlement + carried_over - used';


